import urllib.request, json

pairs = ["BTCUSDT", "ETHUSDT", "XRPUSDT", "XAGUSDT"]
results = {}

# Current price + 24hr stats
for sym in pairs:
    try:
        url = f"https://fapi.asterdex.com/fapi/v1/ticker/24hr?symbol={sym}"
        with urllib.request.urlopen(url, timeout=8) as r:
            d = json.loads(r.read())
        results[sym] = {
            "price": float(d.get("lastPrice", 0)),
            "volume": float(d.get("volume", 0)),
            "quoteVolume": float(d.get("quoteVolume", 0)),
        }
    except Exception as e:
        results[sym] = {"error": str(e)}

# 3-min klines for price change
for sym in pairs:
    try:
        url = f"https://fapi.asterdex.com/fapi/v1/klines?symbol={sym}&interval=1m&limit=4"
        with urllib.request.urlopen(url, timeout=8) as r:
            klines = json.loads(r.read())
        open_3m = float(klines[-4][1])  # open of candle 3 minutes ago
        close_now = float(klines[-1][4])
        pct = (close_now - open_3m) / open_3m * 100
        results[sym]["pct_3m"] = pct
    except Exception as e:
        results[sym]["pct_3m_err"] = str(e)

# Funding rates
for sym in pairs:
    try:
        url = f"https://fapi.asterdex.com/fapi/v1/premiumIndex?symbol={sym}"
        with urllib.request.urlopen(url, timeout=8) as r:
            d = json.loads(r.read())
        results[sym]["funding"] = float(d.get("lastFundingRate", 0)) * 100
    except Exception as e:
        results[sym]["funding_err"] = str(e)

print(json.dumps(results, indent=2))
EOF
